// Guardiao Fernanda — Analisar e Filtrar Alertas (com anti-spam + contador)

const adsData = $('Buscar Ads Ativos').first().json.data || [];
const insightsData = $('Buscar Insights Hoje').first().json.data || [];

const LANCAMENTO = '{{LANCAMENTO_FILTRO}}';
const CPL_TARGET = 14;
const LIMITE_NOVO_GASTO = 40;
const LIMITE_MADURO_GASTO = 42;
const CPL_RUIM_MADURO = 20;
const COOLDOWN_MS = 4 * 60 * 60 * 1000;

const agora = new Date();
const agoraMs = agora.getTime();

// Static data persiste entre execucoes
const workflowStaticData = $getWorkflowStaticData('global');
if (!workflowStaticData.alertasEnviados) {
  workflowStaticData.alertasEnviados = {};
}
const historico = workflowStaticData.alertasEnviados;

// Limpar entradas muito antigas (> 48h) pra nao inchar
const LIMITE_HISTORICO_MS = 48 * 60 * 60 * 1000;
for (const adId of Object.keys(historico)) {
  if (agoraMs - (historico[adId].ultima_vez || 0) > LIMITE_HISTORICO_MS) {
    delete historico[adId];
  }
}

const alertas = [];
const contextoCampanhas = {};

for (const ad of adsData) {
  const adName = ad.name || '';
  const campName = (ad.campaign && ad.campaign.name) || '';
  if (!adName.includes(LANCAMENTO) && !campName.includes(LANCAMENTO)) continue;

  const insight = insightsData.find(i => i.ad_id === ad.id);
  if (!insight) continue;

  const spend = parseFloat(insight.spend || 0);
  const leadsAction = (insight.actions || []).find(a =>
    a.action_type === 'offsite_complete_registration_add_meta_leads' ||
    a.action_type === 'complete_registration'
  );
  const leads = leadsAction ? parseInt(leadsAction.value) : 0;
  const cpl = leads > 0 ? spend / leads : null;
  const freq = parseFloat(insight.frequency || 0);
  const ctr = parseFloat(insight.ctr || 0);

  const createdTime = new Date(ad.created_time);
  const horasVida = (agora - createdTime) / (1000 * 60 * 60);
  const ehNovo = horasVida < 24;

  const campId = (ad.campaign && ad.campaign.id) || insight.campaign_id;
  if (!contextoCampanhas[campId]) {
    contextoCampanhas[campId] = {
      nome: campName || insight.campaign_name,
      ads: [], total_spend: 0, total_leads: 0
    };
  }
  contextoCampanhas[campId].ads.push({nome: adName, spend, leads, cpl});
  contextoCampanhas[campId].total_spend += spend;
  contextoCampanhas[campId].total_leads += leads;

  let motivoAlerta = null;

  if (ehNovo) {
    if (spend > LIMITE_NOVO_GASTO && leads === 0) {
      motivoAlerta = `Anuncio novo (${horasVida.toFixed(1)}h) gastou R$${spend.toFixed(2)} com 0 leads`;
    } else if (spend > LIMITE_NOVO_GASTO && leads === 1 && cpl > CPL_TARGET * 2) {
      motivoAlerta = `Anuncio novo gastou R$${spend.toFixed(2)} com 1 lead (CPL R$${cpl.toFixed(2)}, 2x target)`;
    } else if (spend > LIMITE_NOVO_GASTO && cpl !== null && cpl > CPL_RUIM_MADURO) {
      motivoAlerta = `Anuncio novo com CPL alto: R$${cpl.toFixed(2)} (target R$${CPL_TARGET}), gasto R$${spend.toFixed(2)}`;
    }
  } else {
    if (spend > LIMITE_MADURO_GASTO && leads <= 1) {
      motivoAlerta = `Anuncio maduro gastou R$${spend.toFixed(2)} com ${leads} lead${leads === 1 ? '' : 's'}`;
    } else if (spend > LIMITE_MADURO_GASTO && cpl !== null && cpl > CPL_RUIM_MADURO) {
      motivoAlerta = `Anuncio maduro com CPL alto: R$${cpl.toFixed(2)} (target R$${CPL_TARGET}), gasto R$${spend.toFixed(2)}`;
    }
  }

  if (motivoAlerta) {
    const registro = historico[ad.id];

    // Anti-spam: se alertou nos ultimos 4h, pular
    if (registro && (agoraMs - registro.ultima_vez) < COOLDOWN_MS) {
      continue;
    }

    // Definir numero da notificacao
    const numeroNotificacao = registro ? (registro.contador || 1) + 1 : 1;

    alertas.push({
      ad_id: ad.id, ad_name: adName,
      campaign_id: campId, campaign_name: campName || insight.campaign_name,
      spend, leads, cpl, freq, ctr,
      horas_vida: horasVida, eh_novo: ehNovo,
      motivo: motivoAlerta,
      numero_notificacao: numeroNotificacao
    });

    historico[ad.id] = {
      ultima_vez: agoraMs,
      contador: numeroNotificacao
    };
  }
}

for (const alerta of alertas) {
  const ctx = contextoCampanhas[alerta.campaign_id];
  const cplCampanha = ctx.total_leads > 0 ? ctx.total_spend / ctx.total_leads : null;
  const restanteLeads = ctx.total_leads - alerta.leads;
  const cplCampanhaSemEsse = restanteLeads > 0
    ? (ctx.total_spend - alerta.spend) / restanteLeads : null;
  alerta.campanha_contexto = {
    total_ads: ctx.ads.length,
    total_spend: ctx.total_spend,
    total_leads: ctx.total_leads,
    cpl_campanha: cplCampanha,
    cpl_campanha_sem_esse_ad: cplCampanhaSemEsse
  };
}

if (alertas.length === 0) {
  return [{json: {nenhum_alerta: true}}];
}

return alertas.map(a => ({json: a}));
